mapper.insert:
INSERT INTO queue_items (queue_id, song_id,
       queue_item_position) SELECT #{queueId}, song_id, song_playlist_position FROM
       songs_playlists_relation WHERE playlist_id = #{playlistId}

mapper.select:
SELECT qi.queue_id,
       qi.queue_item_position, qi.song_id FROM queue_items qi JOIN queues q ON qi.queue_id =
       q.queue_id WHERE qi.queue_item_id = #{itemId} AND q.creator_id = #{userId}
